import{_ as e,o as a,c as d,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"TikTok Data & Reporting","description":"","frontmatter":{"title":"TikTok Data & Reporting","slug":"tiktok-data-reporting"},"headers":[],"relativePath":"marketer-hub/tiktok-data-reporting.md","filePath":"marketer-hub/tiktok-data-reporting.md"}'),i={name:"marketer-hub/tiktok-data-reporting.md"};function o(n,t,s,h,c,l){return a(),d("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>After connecting TikTok For Business to Branch, data will seamlessly flow between the two to measure your campaigns&#39; performance. It is helpful to know what kinds of data are passed to each platform to properly compare campaigns and optimize future campaigns. The Branch Dashboard will also populate with helpful reports for campaign measurement.</p><h2 id="mapping-between-tiktok-branch" tabindex="-1">Mapping between TikTok &amp; Branch <a class="header-anchor" href="#mapping-between-tiktok-branch" aria-label="Permalink to &quot;Mapping between TikTok &amp; Branch&quot;">​</a></h2><h3 id="campaign-data-mapping" tabindex="-1">Campaign data mapping <a class="header-anchor" href="#campaign-data-mapping" aria-label="Permalink to &quot;Campaign data mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Branch data</th><th>TikTok data</th><th>Definition</th><th>Possible values</th></tr></thead><tbody><tr><td><code>~campaign</code></td><td>campaign_name</td><td>The advertiser-defined campaign name of the campaign that produced the ad event. This value is not guaranteed unique.</td><td>Light Bright Launch</td></tr><tr><td><code>~campaign_id</code></td><td>campaign_id</td><td>The numeric campaign ID of the campaign that produced the ad event. This value is guaranteed unique.</td><td>15292426</td></tr><tr><td><code>~country</code></td><td>country</td><td>User’s country code</td><td>2-letter country code</td></tr><tr><td><code>~ad_set_name</code></td><td>ad_group_name</td><td>The advertiser-defined ad group name of the campaign that produced the ad event. This value is not guaranteed unique.</td><td>“Example name”</td></tr><tr><td><code>~ad_set_id</code></td><td>ad_group_id</td><td>The numeric ID of the ad group that produced with the ad event.</td><td>235465654654</td></tr><tr><td><code>~ad_name</code> &amp; <code>~creative_name</code></td><td>ad_name</td><td>The advertiser-defined ad name of the campaign that produced the ad event. This value is not guaranteed unique.</td><td>Creative name</td></tr><tr><td><code>~ad_id</code> &amp; &amp; <code>~creative_id</code></td><td>ad_id</td><td>The numeric adID of the campaign that produced the ad event. This value is guaranteed unique.</td><td>123456</td></tr><tr><td><code>~placement</code></td><td>placement</td><td>The advertiser-defined placement name of the campaign that produced the ad event. This value is not guaranteed unique.</td><td>placement</td></tr><tr><td><code>last_attributed_touch_type</code></td><td>attribution_type</td><td>The type of attribution of the last touch event</td><td>CLICK or IMPRESSION</td></tr></tbody></table><h3 id="event-mapping" tabindex="-1">Event mapping <a class="header-anchor" href="#event-mapping" aria-label="Permalink to &quot;Event mapping&quot;">​</a></h3><p>This is the standard Branch events to TikTok for Business pre-defined event mapping. You can choose to select any Branch event you want to link and map the field with one of the predefined TikTok For Business (SAN) event names.</p><table tabindex="0"><thead><tr><th>Branch Event</th><th>TikTok Event</th><th>TikTok Event Enum (For reference)</th></tr></thead><tbody><tr><td>INSTALL</td><td>InstallApp</td><td>0</td></tr><tr><td>OPEN</td><td>LaunchAPP</td><td>129</td></tr><tr><td>ACHIEVE_LEVEL</td><td>AchieveLevel</td><td>40</td></tr><tr><td>ADD_PAYMENT_INFO</td><td>AddPaymentInfo</td><td>127</td></tr><tr><td>ADD_TO_WISHLIST</td><td>AddToWishlist</td><td>128</td></tr><tr><td>INITIATE_PURCHASE</td><td>Checkout</td><td>20</td></tr><tr><td>COMPLETE_TUTORIAL</td><td>CompleteTutorial</td><td>131</td></tr><tr><td>CLICK_AD</td><td>InAppADClick</td><td>132</td></tr><tr><td>VIEW_AD</td><td>InAppAdImpr</td><td>133</td></tr><tr><td>ADD_TO_CART</td><td>AddToCart</td><td>22</td></tr><tr><td>LOGIN</td><td>Login</td><td>114</td></tr><tr><td>PURCHASE</td><td>Purchase</td><td>2</td></tr><tr><td>RATE</td><td>Rate</td><td>138</td></tr><tr><td>COMPLETE_REGISTRATION</td><td>Registration</td><td>1</td></tr><tr><td>SEARCH</td><td>Search</td><td>140</td></tr><tr><td>SPEND_CREDITS</td><td>SpendCredits</td><td>141</td></tr><tr><td>START_TRIAL</td><td>StartTrial</td><td>142</td></tr><tr><td>SUBSCRIBE</td><td>Subscribe</td><td>143</td></tr><tr><td>UNLOCK_ACHIEVEMENT</td><td>UnlockAchievement</td><td>144</td></tr><tr><td>VIEW_ITEM</td><td>ViewContent</td><td>29</td></tr><tr><td></td><td>CreateGroup</td><td>135</td></tr><tr><td></td><td>CreateRole</td><td>39</td></tr><tr><td></td><td>GenerateLead</td><td>24</td></tr><tr><td></td><td>JoinGroup</td><td>134</td></tr><tr><td></td><td>LoanApplication</td><td>118</td></tr><tr><td></td><td>LoanApproval</td><td>105</td></tr><tr><td></td><td>LoanDisbursal</td><td>103</td></tr></tbody></table><h2 id="branch-dashboard-reports" tabindex="-1">Branch Dashboard reports <a class="header-anchor" href="#branch-dashboard-reports" aria-label="Permalink to &quot;Branch Dashboard reports&quot;">​</a></h2><h4 id="available-dimensions-to-compare-by" tabindex="-1">Available dimensions to compare by <a class="header-anchor" href="#available-dimensions-to-compare-by" aria-label="Permalink to &quot;Available dimensions to compare by&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Dimension</th><th>Supported?</th></tr></thead><tbody><tr><td>Clicks</td><td>✅ Yes</td></tr><tr><td>Cost</td><td>✅ Yes</td></tr><tr><td>Impressions</td><td>✅ Yes</td></tr><tr><td>Feature</td><td>✅ Yes</td></tr><tr><td>Channel</td><td>✅ Yes</td></tr><tr><td>Campaign</td><td>✅ Yes</td></tr><tr><td>Tags</td><td>❌ No</td></tr><tr><td>Stage</td><td>❌ No</td></tr><tr><td>Ad Partner</td><td>✅ Yes</td></tr><tr><td>OS</td><td>✅ Yes</td></tr><tr><td>Platform</td><td>✅ Yes</td></tr><tr><td>Keyword</td><td>❌ No</td></tr><tr><td>Campaign ID</td><td>✅ Yes</td></tr><tr><td>Ad Set Name</td><td>✅ Yes</td></tr><tr><td>Ad Set ID</td><td>✅ Yes</td></tr><tr><td>Ad Name</td><td>✅ Yes</td></tr><tr><td>Ad ID</td><td>✅ Yes</td></tr><tr><td>Placement</td><td>✅ Yes</td></tr><tr><td>Last Touch Type</td><td>✅ Yes</td></tr></tbody></table><h4 id="cost-metrics-data" tabindex="-1">Cost metrics data <a class="header-anchor" href="#cost-metrics-data" aria-label="Permalink to &quot;Cost metrics data&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Analytics Tag</th><th>Description</th><th>Used For</th></tr></thead><tbody><tr><td>Cost</td><td>Total cost</td><td>Sum of cost</td></tr><tr><td>ROI</td><td>Return on investment. Profit as a percentage of cost</td><td>(Revenue-Cost) * 100 /Cost</td></tr><tr><td>ROAS</td><td>Return on Ad Spent. Revenue as a percentage of cost</td><td>Revenue/Cost</td></tr><tr><td>eCPI</td><td>Effective cost per install. The total cost of the campaign divided by the number of installs driven.</td><td>Cost / Installs (eo_installs)</td></tr><tr><td>eCPC</td><td>Effective cost per click. The total cost of the campaign divided by the number of clicks.</td><td>Cost / Clicks (eo_clicks)</td></tr><tr><td>eCPM</td><td>Effective cost per milli (thousand impressions). The total cost of the campaign divided by the number of impressions / 1000</td><td>Cost / (Impressions / 1000) (eo_impressions)</td></tr><tr><td>eCPA</td><td>Effective cost per purchase</td><td>Cost / Purchases</td></tr></tbody></table><h4 id="engagement-metrics" tabindex="-1">Engagement metrics <a class="header-anchor" href="#engagement-metrics" aria-label="Permalink to &quot;Engagement metrics&quot;">​</a></h4><p>You can view data for click-through and view-through engagement conversion metrics for TikTok for Business. Here are the following supported engagement types:</p><table tabindex="0"><thead><tr><th>Engagement Type</th><th>Attribution Support</th></tr></thead><tbody><tr><td>Engaged View</td><td>Click-Through</td></tr><tr><td>Engaged Click</td><td>Click-Through</td></tr><tr><td>Click to Store</td><td>Click-Through</td></tr><tr><td>View</td><td>View-Through</td></tr></tbody></table><p>You can view these through Dashboard Reports or exports:</p><table tabindex="0"><thead><tr><th>Report/Export</th><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Report</td><td><code>touch subtype</code></td><td><code>engaged_view</code>, <code>engaged_click</code>, <code>click_to_store</code>, <code>view</code></td></tr><tr><td>Dashboard Custom Exports</td><td>Column</td><td>Touch Subtype</td></tr><tr><td>Custom Exports API</td><td><code>fields</code></td><td><code>last_attributed_touch_data_tilde_touch_subtype</code></td></tr></tbody></table><h2 id="possible-data-discrepancies" tabindex="-1">Possible data discrepancies <a class="header-anchor" href="#possible-data-discrepancies" aria-label="Permalink to &quot;Possible data discrepancies&quot;">​</a></h2><p>TikTok for Business and Branch use distinct attribution models. This may cause discrepancies between TikTok for Business and Branch. While we work closely with TikTok for Business, to minimize these discrepancies, advertisers need to be aware of potential causes.</p><p>The table below describes possible reasons for discrepancies between the TikTok Ads Manager and the Branch Dashboard.</p><table tabindex="0"><thead><tr><th></th><th>Branch</th><th>TikTok for Business</th></tr></thead><tbody><tr><td>Click-through attribution window</td><td>The default window is 1 day for session start. More details <a href="./attribution-windows-link-settings.html">here</a>.</td><td>The default window is 7 days. This window can be configured either 1 day or 7 day.</td></tr><tr><td>View-through attribution window</td><td>The default window is 1 day for session start. More details <a href="./attribution-windows-link-settings.html">here</a>.</td><td>The default window is 1 day. This window can be configured either 1 day or off.</td></tr><tr><td>Multi-channel source attribution</td><td>Branch attributes based on Last Touch; though, you may view different ad network touches using Branch. More details <a href="./multi-touch-attribution.html">here</a>.</td><td>TikTok attributes installs to itself if the install occurs within the attribution window following the ad engagement (view, click, etc.), regardless of other media sources</td></tr><tr><td>Different time zones</td><td>Timezone can be configured in the <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Profile Tab of Account Settings.</a></td><td><a href="https://ads.tiktok.com/help/article/time-zone" target="_blank" rel="noreferrer">TikTok&#39;s timezone</a> (displayed next to the date range) can&#39;t be adjusted. It was configured while creating the ad account.</td></tr><tr><td>iOS attribution</td><td>Branch combines iOS attribution across <a href="./skadnetwork-dashboard-reports.html#skan-unified-view">all integrated ad networks including SKAN</a></td><td>For iOS apps, the TikTok ads manager only displays SKAN attribution results</td></tr><tr><td>In-app event attribution periods</td><td>Branch attributes in-app events to the last touch ad engagement. Separate attribution windows can be configured for in-app events.</td><td>Attribution on each platform may differ based on period windows from the initial install: TikTok attributes post-install in-app events up to 90 days from the install date.</td></tr><tr><td>Click-Date Cohort vs. Install-Date Cohort</td><td>Branch shows installs as well as post-install events in cohorts based on the date of the ad engagement (ad click/ad view). More details <a href="./cohort-analytics.html">here</a>.</td><td>TikTok shows installs as well as post-install events in cohorts based on the date of the ad engagement (ad click/ad view)</td></tr></tbody></table><p>Learn more about possible data discrepancies <a href="https://ads.tiktok.com/help/article/about-reporting-discrepancies-between-tiktok-ads-manager-and-mmps?lang=en" target="_blank" rel="noreferrer">here</a>.</p><h2 id="ios-real-time-conversion-reporting-recommended" tabindex="-1">iOS real-time conversion reporting (recommended) <a class="header-anchor" href="#ios-real-time-conversion-reporting-recommended" aria-label="Permalink to &quot;iOS real-time conversion reporting (recommended)&quot;">​</a></h2><p>To minimize data discrepancies between Branch and TikTok Ads Manager for iOS campaigns, we recommend enabling <a href="https://ads.tiktok.com/help/article/about-ios-real-time-conversion-reporting" target="_blank" rel="noreferrer">iOS real-time conversion reporting</a>. This feature provides near real-time, granular conversion data for iOS 14.5+ campaigns and replaces the delayed, aggregated results from SKAN with detailed reporting at the campaign, ad group, and ad level.</p><p>When enabled, iOS real-time reporting helps align the numbers reported in Branch with those in TikTok Ads Manager because we use a shared attribution signal. This reduces the timing and methodology gaps described above.</p><h4 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h4><p>The benefits of iOS real-time conversion reporting include:</p><ul><li>Near real-time data: Conversion metrics are available in close to real time.</li><li>Granular reporting: Performance data is broken down at the campaign, ad group, and ad level.</li><li>Goal-based bidding: Supports TikTok bidding strategies with more responsive data.</li><li>Unlimited iOS campaigns: When SKAN reporting is turned off, TikTok’s campaign quota no longer applies.</li></ul><h4 id="enable-ios-real-time-conversion-reporting" tabindex="-1">Enable iOS real-time conversion reporting <a class="header-anchor" href="#enable-ios-real-time-conversion-reporting" aria-label="Permalink to &quot;Enable iOS real-time conversion reporting&quot;">​</a></h4><p>To use iOS real-time conversion reporting with Branch, <strong>you must first enable Predictive Aggregate Measurement (PAM)</strong>. For instructions, see our <a href="./predictive-aggregate-measurement.html#implementation">PAM guide</a>.</p><p>Once PAM is enabled, you can verify eligibility in TikTok Ads Manager when creating an iOS 14 dedicated campaign. If the app has sufficient data signals, the message “Your app is eligible for iOS real-time reporting” will appear.</p><p>.png)</p><h4 id="data-considerations" tabindex="-1">Data considerations <a class="header-anchor" href="#data-considerations" aria-label="Permalink to &quot;Data considerations&quot;">​</a></h4><p>Take the following considerations into account when deciding whether to use SKAN or iOS real-time reporting:</p><table tabindex="0"><thead><tr><th>Area</th><th>With SKAN</th><th>With iOS real-time reporting</th></tr></thead><tbody><tr><td>Data freshness</td><td>Delayed</td><td>Near real-time</td></tr><tr><td>Reporting granularity</td><td>Aggregated; limited campaign-level data</td><td>Campaign, ad group, and ad level</td></tr><tr><td>Attribution model</td><td>Apple’s SKAdNetwork framework</td><td>TikTok’s modeled attribution via MMP signals</td></tr><tr><td>Campaign quota</td><td>Limited by SKAN campaign ID slots</td><td>Unlimited (when SKAN is turned off)</td></tr><tr><td>SKAN reporting</td><td>Available in both TikTok Ads Manager and <a href="https://help.branch.io/marketer-hub/docs/skadnetwork-dashboard-reports" target="_blank" rel="noreferrer">Branch</a></td><td>Not available if SKAN attribution is disabled</td></tr></tbody></table><h2 id="app-activity-for-non-app-promotion-web-campaigns" tabindex="-1">App activity for non-app promotion web campaigns <a class="header-anchor" href="#app-activity-for-non-app-promotion-web-campaigns" aria-label="Permalink to &quot;App activity for non-app promotion web campaigns&quot;">​</a></h2><p>You can track app activities, such as installs and in-app purchases, for non-app promotion campaigns in TikTok Ads Manager. For example, if your web conversion or traffic campaign directs users to a web landing page, you can still measure app installs and related in-app events.</p><p>To learn how to do this, check out <a href="https://ads.tiktok.com/help/article/how-to-measure-app-activity-for-non-app-promotion-campaigns?lang=en" target="_blank" rel="noreferrer">TikTok&#39;s instructions</a>.</p>',39)])])}const u=e(i,[["render",o]]);export{m as __pageData,u as default};
